  ('real-estate-moex-00889', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依土地法第100條之規定，出租人因下列何項情形，得收回房屋？ 承租人積欠租金額，除擔保金抵償外，達1個月 承租人損壞出租人之房屋或附著財物，為相當之賠償時 出租人收回自住或重新建築時 承租人以房屋供合於法令之使用時', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
