  ('real-estate-moex-00891', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列有關都市計畫主要計畫之擬定及核定程序規定，何者錯誤？ 主要計畫擬定後，應先送由該管政府或鄉、鎮、縣轄市都市計畫委員會審議 縣政府所在地及縣轄市之主要計畫由內政部核定 地方政府於接到主要計畫核定公文之日起30日內，應將主要計畫書、圖發布實施 主要計畫經該管政府都市計畫委員會審議後，應公開展覽30天及舉行說明會', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
