  ('real-estate-moex-00893', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列何者不符合申請自用住宅用地之土地增值稅稅率規定？ 出售前1年內，未營業使用或出租 都市土地面積未超過3公畝部分或非都市土地面積未超過7公畝部分 土地所有權人與其配偶及未成年之受扶養親屬，適用自用住宅用地稅率者，以一處為限 土地所有權人或其配偶、直系親屬於該地辦竣戶籍登記', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
